#include <stdio.h>
#include <string.h>
#include <ctype.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char buf[1010];
    // consume the newline after T
    getchar();
    while (T--) {
        if (!fgets(buf, sizeof(buf), stdin)) break;
        size_t n = strlen(buf);
        // remove trailing newline if present
        if (n && buf[n-1] == '\n') buf[--n] = '\0';
        int ok = 1;
        if (n < 4) ok = 0; // need at least </a>
        else if (buf[0] != '<' || buf[1] != '/' || buf[n-1] != '>') ok = 0;
        else {
            // body is from index 2 to n-2 inclusive
            if (n == 4) ok = 0; // empty body
            else {
                for (size_t i = 2; i < n-1; ++i) {
                    if (!isdigit((unsigned char)buf[i]) && !(buf[i] >= 'a' && buf[i] <= 'z')) {
                        ok = 0;
                        break;
                    }
                }
            }
        }
        puts(ok ? "Success" : "Error");
    }
    return 0;
}

