            string body = s.substr(2, s.size() - 3);
            if (body.empty()) ok = false;
            else {
                for (char c : body) {
                    if (!isdigit(c) && !(c >= 'a' && c <= 'z')) { ok = false; break; }
                }
            }
        }
        cout << (ok ? "Success" : "Error") << '\n';
    }
    return 0;
}

