import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            String s = br.readLine();
            boolean ok = true;
            if (s.length() < 4) ok = false;
            else if (s.charAt(0) != '<' || s.charAt(1) != '/' || s.charAt(s.length() - 1) != '>') ok = false;
            else {
                String body = s.substring(2, s.length() - 1);
                if (body.isEmpty()) ok = false;
                else {
                    for (char c : body.toCharArray()) {
                        if (!Character.isDigit(c) && !(c >= 'a' && c <= 'z')) { ok = false; break; }
                    }
                }
            }
            out.append(ok ? "Success" : "Error").append('\n');
        }
        System.out.print(out.toString());
    }
}

