#!/usr/bin/env python3
import sys

def is_valid(tag: str) -> bool:
    if len(tag) < 4:
        return False
    if not (tag.startswith("</") and tag.endswith(">")):
        return False
    body = tag[2:-1]
    if not body:
        return False
    for ch in body:
        if not (ch.isdigit() or ('a' <= ch <= 'z')):
            return False
    return True

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out = []
    for i in range(1, T + 1):
        tag = data[i].strip()
        out.append("Success" if is_valid(tag) else "Error")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

